        iv = os.urandom(12)

        result = _aes_gcm_encrypt(data.encode("utf-8"), key, iv, aad_buffer)
        combined = (
            result["iv"]
            + result["tag"]
            + prefix_len_buffer
            + key_blob
            + result["ciphertext"]
        )
        return base64.b64encode(combined).decode("utf-8")

